fn test_pure_red() {
        let (h, s, v) = rgb_to_hsv(1.0, 0.0, 0.0);
        assert!((h - 0.0).abs() < 1e-5, "Red hue: expected 0, got {h}");
        assert!((s - 1.0).abs() < 1e-5, "Red sat: expected 1, got {s}");
        assert!((v - 1.0).abs() < 1e-5, "Red val: expected 1, got {v}");
    }
